def gen(rng, size):
    n = max(1, min(size, 100000))
    alphabet = 'abcde'
    source = ''.join(rng.choice(alphabet) for _ in range(n))
    original = []
    changed = []
    cost = []
    for a in alphabet:
        for b in alphabet:
            if a != b and rng.random() < 0.5:
                original.append(a)
                changed.append(b)
                cost.append(rng.randint(1, 1000))
    if not original:
        original = ['a']
        changed = ['b']
        cost = [1]
    target_list = list(source)
    for i in range(n):
        if rng.random() < 0.4:
            target_list[i] = rng.choice(alphabet)
    target = ''.join(target_list)
    return [source, target, original, changed, cost]

