import heapq


class Solution:
    def minimumCost(self, source, target, original, changed, cost):
        adj = [[] for _ in range(26)]
        for o, c, w in zip(original, changed, cost):
            adj[ord(o) - 97].append((ord(c) - 97, w))

        def dijkstra(start):
            dist = [float('inf')] * 26
            dist[start] = 0
            pq = [(0, start)]
            while pq:
                d, u = heapq.heappop(pq)
                if d > dist[u]:
                    continue
                for v, w in adj[u]:
                    nd = d + w
                    if nd < dist[v]:
                        dist[v] = nd
                        heapq.heappush(pq, (nd, v))
            return dist

        dists = [dijkstra(i) for i in range(26)]
        total = 0
        for a, b in zip(source, target):
            if a == b:
                continue
            d = dists[ord(a) - 97][ord(b) - 97]
            if d == float('inf'):
                return -1
            total += d
        return total

