class Solution:
    def minimumCost(self, source: str, target: str, original: List[str], changed: List[str], cost: List[int]) -> int:
        INF = float('inf')
        dist = [[INF] * 26 for _ in range(26)]
        for i in range(26):
            dist[i][i] = 0
        for o, c, w in zip(original, changed, cost):
            u = ord(o) - 97
            v = ord(c) - 97
            if w < dist[u][v]:
                dist[u][v] = w
        for k in range(26):
            dk = dist[k]
            for i in range(26):
                dik = dist[i][k]
                if dik == INF:
                    continue
                di = dist[i]
                for j in range(26):
                    nd = dik + dk[j]
                    if nd < di[j]:
                        di[j] = nd
        total = 0
        for a, b in zip(source, target):
            if a == b:
                continue
            u = ord(a) - 97
            v = ord(b) - 97
            if dist[u][v] == INF:
                return -1
            total += dist[u][v]
        return total

